CREATE TABLE sys_modules (
    id INTEGER NOT NULL,
    name VARCHAR NOT NULL,
    key_translate VARCHAR NOT NULL,
    u_path VARCHAR NOT NULL,
    parent_id INTEGER,
    CONSTRAINT app_modules_p_key PRIMARY KEY (id)
);

